#include <bits/stdc++.h>
using namespace std;
const long long MOD1 = 1000000007;
const long long MOD2 = 998244353;
typedef long long ll;
typedef pair<ll, ll> P;
const long long INF = 1e17;
template <typename T>
void input_arr(vector<T>& A, ll N) {
    for (ll i = 0; i < N; i++) {
        cin >> A[i];
    }
}
void input_arr(vector<P>& A, ll N) {
    for (ll i = 0; i < N; i++) {
        cin >> A[i].first >> A[i].second;
    }
}
vector<string>A(9); //盤面
ll dx[4] = {-1, 0, 1, 0}, dy[4] = {0, 1, 0, -1};
ll px = 8, py = 4; //相手の座標
ll mx = 0, my = 4; //自分の座標
bool partner() { //相手の動き
    ll task; cin >> task;
    if (task == 3) return true; //ゲーム終了
    if (!task) { //移動をする場合
        ll d; cin >> d;
        //d = 0 : 上に移動
        //d = 1 : 右に移動
        //d = 2 : 下に移動
        //d = 3 : 左に移動
        px += dx[d];
        py += dy[d];
        A[px][py] = '.';
    }
    else {
        ll x, y; cin >> x >> y;
    }
    return false;
}
ll dis(ll ax, ll ay, ll bx, ll by) { //マンハッタン距離を計算
    return abs(ax - bx) + abs(ay - by);
}
void solve() {
    ll before = 2;
    string firsec; cin >> firsec; //先手か後手か
    for (ll i = 0; i < 9; i++) {
        cin >> A[i];
    }
    if (firsec == "Second") {
        if (partner()) return;
        before = 0;
    }
    else swap(px, mx);

    while (true) {
        ll u = 0, d = 0, l = 0, r = 0;
        for (ll i = 0; i < 9; i++) {
            for (ll j = 0; j < 9; j++) {
                if (dis(i, j, mx, my) > dis(i, j, px, py)) continue; //(i,　j) の点に、自分より相手の方が近い場合は除外
                //if (firsec == "Second" && dis(i, j, mx, my) == dis(i, j, px, py)) continue;
                if (A[i][j] == '.') continue; //(i, j) にリンゴがなかったら除外
                if (i <= mx && abs(j - my) <= mx - i) u += (10 - dis(i, j, mx, my)) * (10 - dis(i, j, mx, my));
                if (i >= mx && abs(j - my) <= i - mx) d += (10 - dis(i, j, mx, my)) * (10 - dis(i, j, mx, my));
                if (j <= my && abs(i - mx) <= my - j) l += (10 - dis(i, j, mx, my)) * (10 - dis(i, j, mx, my));
                if (j >= my && abs(i - mx) <= j - my) r += (10 - dis(i, j, mx, my)) * (10 - dis(i, j, mx, my));
            }
        }

        vector<ll>v(4, 1);
        for (ll i = 0; i < 4; i++) {
            ll nx = mx + dx[i], ny = my + dy[i];
            if (0 <= nx && nx < 9 && 0 <= ny && ny < 9) {
                if (A[nx][ny] == '#') v[i] = 1000000000;
            }
        }
        v[before^2] = -1e9;
        u *= v[0];
        r *= v[1];
        d *= v[2];
        l *= v[3];
        if (u >= r && u >= d && u >= l && mx > 0) {
            cout << "0 0" << endl;
            mx--;
            before = 0;
        }
        else if (r >= u && r >= d && r >= l && my < 8) {
            cout << "0 1" << endl;
            my++;
            before = 1;
        }
        else if (d >= u && d >= r && d >= l && mx < 8) {
            cout << "0 2" << endl;
            mx++;
            before = 2;
        }
        else if (l >= u && l >= r && l >= d && my > 0) {
            cout << "0 3" << endl;
            my--;
            before = 3;
        }
        else if (0 < mx) {
            cout << "0 0" << endl;
            mx--; before = 0;
        }
        else if (0 < my) {
            cout << "0 3" << endl;
            my--; before = 3;
        }
        else if (mx < 8) {
            cout << "0 2" << endl;
            mx++;
            before = 2;
        }
        else {
            cout << "0 1" << endl;
            my++;
            before = 1;
        }
        A[mx][my] = '.';
        if (partner()) return;
    }
}
int main() {
    ll T=1;//cin>>T;
    while(T--)solve();
}
